import { Component } from '@angular/core';

@Component({
  selector: 'app-download',
  templateUrl: './download.component.html',
  styleUrls: ['./download.component.css']
})
export class DownloadComponent {
  downloads = [
    {
      platform: 'Windows',
      icon: 'assets/download-windows.png',
      url: 'https://github.com/foraydev/gravitas-releases/releases/download/v0.4.0/Glumion.Windows.zip'
    },
    {
      platform: 'Mac',
      icon: 'assets/download-mac.png',
      url: '[INSERT_MAC_DOWNLOAD_LINK]'
    },
    {
      platform: 'Steam Deck',
      icon: 'assets/download-steam-deck.svg',
      url: 'https://github.com/foraydev/gravitas-releases/releases/download/v0.4.0/Glumion.Steam.Deck.zip'
    }
  ];
}
<section class="download" id="download">
  <div class="download-container">
    <h2 class="download-title">Download Glumion</h2>
    <div class="download-buttons">
      <a *ngFor="let download of downloads" [href]="download.url" class="download-btn">
        <img [src]="download.icon" [alt]="download.platform" class="btn-icon">
        <span class="btn-text">{{ download.platform }}</span>
      </a>
    </div>
  </div>
</section>
